#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int check(int n) {
        string bin_str;
        while (n) {
            bin_str += (n % 2 == 0 ? '0' : '1');
            n /= 2;
        }
        string rev_bin_str = bin_str;
        reverse(rev_bin_str.begin(), rev_bin_str.end());
        return bin_str == rev_bin_str ? 1 : 0;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int _;
    if (!(cin >> _)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    int ans = sol.check(n);
    cout << ans << endl;
    return 0;
}
